    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_generic_d8_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_generic_moe_kernel  [q4/int8/generic/moe]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_generic_moe_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        for (int di = 0; di < d_inner; di++) {
            float fwd_so = fwd_scan_out[idx * d_inner + di];
            float bwd_so = bwd_scan_out[idx * d_inner + di];
            fwd_acc += s_out_fwd[dm * d_inner + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * d_inner + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_generic_moe(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_generic_moe_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_generic_moe_d16_kernel  [q4/int8/generic/moe/d16]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_generic_moe_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 16; di++) {
            float fwd_so = fwd_scan_out[idx * 16 + di];
            float bwd_so = bwd_scan_out[idx * 16 + di];
            fwd_acc += s_out_fwd[dm * 16 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 16 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_generic_moe_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_generic_moe_d16_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_generic_moe_d8_kernel  [q4/int8/generic/moe/d8]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=8>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_generic_moe_d8_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 8; di++) {
            float fwd_so = fwd_scan_out[idx * 8 + di];
            float bwd_so = bwd_scan_out[idx * 8 + di];
            fwd_acc += s_out_fwd[dm * 8 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 8 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_generic_moe_d8(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_generic_moe_d8_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_kernel  [q4/int8/cpasync]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        for (int di = 0; di < d_inner; di++) {
            float fwd_so = fwd_scan_out[idx * d_inner + di];
            float bwd_so = bwd_scan_out[idx * d_inner + di];
            fwd_acc += s_out_fwd[dm * d_inner + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * d_inner + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_d16_kernel  [q4/int8/cpasync/d16]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 16; di++) {
            float fwd_so = fwd_scan_out[idx * 16 + di];
            float bwd_so = bwd_scan_out[idx * 16 + di];
            fwd_acc += s_out_fwd[dm * 16 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 16 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_d16_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_d8_kernel  [q4/int8/cpasync/d8]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=8>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_d8_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 8; di++) {
            float fwd_so = fwd_scan_out[idx * 8 + di];
            float bwd_so = bwd_scan_out[idx * 8 + di];
            fwd_acc += s_out_fwd[dm * 8 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 8 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync_d8(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_d8_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_moe_kernel  [q4/int8/cpasync/moe]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_moe_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        for (int di = 0; di < d_inner; di++) {
            float fwd_so = fwd_scan_out[idx * d_inner + di];
            float bwd_so = bwd_scan_out[idx * d_inner + di];
            fwd_acc += s_out_fwd[dm * d_inner + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * d_inner + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync_moe(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_moe_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_moe_d16_kernel  [q4/int8/cpasync/moe/d16]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_moe_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 16; di++) {
            float fwd_so = fwd_scan_out[idx * 16 + di];
            float bwd_so = bwd_scan_out[idx * 16 + di];
            fwd_acc += s_out_fwd[dm * 16 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 16 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync_moe_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_moe_d16_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int8_cpasync_moe_d8_kernel  [q4/int8/cpasync/moe/d8]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=8>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int8_cpasync_moe_d8_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const int8_t* __restrict__ expert_W1_q,
    const int8_t* __restrict__ expert_b1_q,
    const int8_t* __restrict__ expert_W2_q,
    const int8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    const bool* __restrict__ active_mask,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Phase 1: cp.async prefetch out_proj + GRU weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        const float* src = (i < op_size) ? &out_proj_fwd_W[i] : &out_proj_bwd_W[i - op_size];
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
        __pipeline_memcpy_async(&smem[i], src, sizeof(float));
    #else
        smem[i] = *src;
    #endif
    }

    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size) {
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
            __pipeline_memcpy_async(&gru_dst[gru_offset + i], &gru_gmem[seg][i], sizeof(float));
    #else
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
    #endif
        }
        gru_offset += gru_sizes[seg];
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    #endif

    // INT8 dequantize expert weights on load into shared memory
    for (int i = tid; i < num_experts * expert_hidden; i += block_size) {
        s_expert_W1[i] = static_cast<float>(expert_W1_q[i]) * expert_W1_scale;
        s_expert_b1[i] = static_cast<float>(expert_b1_q[i]) * expert_b1_scale;
        s_expert_W2[i] = static_cast<float>(expert_W2_q[i]) * expert_W2_scale;
    }
    for (int i = tid; i < num_experts; i += block_size) {
        s_expert_b2[i] = static_cast<float>(expert_b2_q[i]) * expert_b2_scale;
    }
    #if GROK_CUDA && defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
    __pipeline_commit();
    __pipeline_wait_prior(0);
    #endif
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 8; di++) {
            float fwd_so = fwd_scan_out[idx * 8 + di];
            float bwd_so = bwd_scan_out[idx * 8 + di];
            fwd_acc += s_out_fwd[dm * 8 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 8 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int8_cpasync_moe_d8(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int8_cpasync_moe_d8_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int4_generic_kernel  [q4/int4/generic]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int4_generic_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const uint8_t* __restrict__ expert_W1_q,
    const uint8_t* __restrict__ expert_b1_q,
    const uint8_t* __restrict__ expert_W2_q,
    const uint8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    // INT4 dequantize: unpack 2 values per byte into shared memory
    const int exp_total = num_experts * expert_hidden;
    for (int i = tid; i < (exp_total + 1) / 2; i += block_size) {
        float lo, hi;
        unpack_int4_gen(expert_W1_q[i], expert_W1_scale, lo, hi);
        s_expert_W1[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_W1[2*i + 1] = hi;
        unpack_int4_gen(expert_b1_q[i], expert_b1_scale, lo, hi);
        s_expert_b1[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_b1[2*i + 1] = hi;
        unpack_int4_gen(expert_W2_q[i], expert_W2_scale, lo, hi);
        s_expert_W2[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_W2[2*i + 1] = hi;
    }
    for (int i = tid; i < (num_experts + 1) / 2; i += block_size) {
        float lo, hi;
        unpack_int4_gen(expert_b2_q[i], expert_b2_scale, lo, hi);
        s_expert_b2[2*i] = lo;
        if (2*i + 1 < num_experts) s_expert_b2[2*i + 1] = hi;
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        for (int di = 0; di < d_inner; di++) {
            float fwd_so = fwd_scan_out[idx * d_inner + di];
            float bwd_so = bwd_scan_out[idx * d_inner + di];
            fwd_acc += s_out_fwd[dm * d_inner + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * d_inner + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int4_generic(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor mu,
    torch::Tensor gru_state,
    torch::Tensor fwd_scan_out,
    torch::Tensor bwd_scan_out,
    float rescale, float alpha, float lamb_eff,
    float beta1, float beta2, float lr,
    float wd_eff, float eps, float bc1, float bc2,
    int global_step,
    int d_model, int d_inner,
    int gru_hidden, int num_heads, int pk_dim,
    int expert_hidden, int num_experts
) {
    const int N = grad.numel();
    if (N == 0) return;
    const int grid = (N + 256 - 1) / 256;
    // TODO: compute shared memory size and launch sg2_fused_elem_q4_int4_generic_kernel
    // Shared memory = 2*op_size + 3*gru_mat_size + 3*gru_hidden
    //               + 3*num_experts*expert_hidden + num_experts (all float)
}

// ═══════════════════════════════════════════════════════════
//  sg2_fused_elem_q4_int4_generic_d16_kernel  [q4/int4/generic/d16]
// ═══════════════════════════════════════════════════════════

template <typename scalar_t, int D_INNER=16>
__launch_bounds__(256, 2)
__global__ void sg2_fused_elem_q4_int4_generic_d16_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    const scalar_t* __restrict__ sharpness,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ mu,
    __nv_bfloat16* __restrict__ gru_state,
    const float* __restrict__ fwd_scan_out,
    const float* __restrict__ bwd_scan_out,
    const float* __restrict__ out_proj_fwd_W,
    const float* __restrict__ out_proj_bwd_W,
    const float* __restrict__ gru_Wz, const float* __restrict__ gru_bz,
    const float* __restrict__ gru_Wr, const float* __restrict__ gru_br,
    const float* __restrict__ gru_Wh, const float* __restrict__ gru_bh,
    const float* __restrict__ peer_query_Ws,
    const float* __restrict__ prod_keys_A,
    const float* __restrict__ prod_keys_B,
    const uint8_t* __restrict__ expert_W1_q,
    const uint8_t* __restrict__ expert_b1_q,
    const uint8_t* __restrict__ expert_W2_q,
    const uint8_t* __restrict__ expert_b2_q,
    const float expert_W1_scale,
    const float expert_b1_scale,
    const float expert_W2_scale,
    const float expert_b2_scale,
    const float rescale, const float alpha, const float lamb_eff,
    const float beta1, const float beta2, const float lr,
    const float wd_eff, const float eps, const float bc1, const float bc2,
    const unsigned global_step,
    int* __restrict__ expert_counts,
    const int N, const int d_model, const int d_inner,
    const int gru_hidden, const int num_heads, const int pk_dim,
    const int expert_hidden, const int num_experts
) {
    const int gru_input_dim = 2 + 2 * d_model;
    const int gru_row_len = gru_input_dim + gru_hidden;
    const int op_size = d_model * d_inner;
    const int gru_mat_size = gru_hidden * gru_row_len;

    extern __shared__ float smem[];

    // Shared memory layout: out_proj -> GRU weights -> expert weights (all FP32)
    float* s_out_fwd = smem;
    float* s_out_bwd = smem + op_size;
    float* s_gru_Wz = s_out_bwd + op_size;
    float* s_gru_Wr = s_gru_Wz + gru_mat_size;
    float* s_gru_Wh = s_gru_Wr + gru_mat_size;
    float* s_gru_bz = s_gru_Wh + gru_mat_size;
    float* s_gru_br = s_gru_bz + gru_hidden;
    float* s_gru_bh = s_gru_br + gru_hidden;
    float* s_expert_W1 = s_gru_bh + gru_hidden;
    float* s_expert_b1 = s_expert_W1 + num_experts * expert_hidden;
    float* s_expert_W2 = s_expert_b1 + num_experts * expert_hidden;
    float* s_expert_b2 = s_expert_W2 + num_experts * expert_hidden;

    const int tid = threadIdx.x;
    const int block_size = blockDim.x;

    // Load out_proj weights
    for (int i = tid; i < 2 * op_size; i += block_size) {
        if (i < op_size) smem[i] = out_proj_fwd_W[i];
        else smem[i] = out_proj_bwd_W[i - op_size];
    }
    // Load GRU weights
    const float* gru_gmem[] = {gru_Wz, gru_Wr, gru_Wh, gru_bz, gru_br, gru_bh};
    int gru_sizes[] = {gru_mat_size, gru_mat_size, gru_mat_size, gru_hidden, gru_hidden, gru_hidden};
    float* gru_dst = s_gru_Wz;
    int gru_offset = 0;
    for (int seg = 0; seg < 6; seg++) {
        for (int i = tid; i < gru_sizes[seg]; i += block_size)
            gru_dst[gru_offset + i] = gru_gmem[seg][i];
        gru_offset += gru_sizes[seg];
    }

    // INT4 dequantize: unpack 2 values per byte into shared memory
    const int exp_total = num_experts * expert_hidden;
    for (int i = tid; i < (exp_total + 1) / 2; i += block_size) {
        float lo, hi;
        unpack_int4_gen(expert_W1_q[i], expert_W1_scale, lo, hi);
        s_expert_W1[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_W1[2*i + 1] = hi;
        unpack_int4_gen(expert_b1_q[i], expert_b1_scale, lo, hi);
        s_expert_b1[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_b1[2*i + 1] = hi;
        unpack_int4_gen(expert_W2_q[i], expert_W2_scale, lo, hi);
        s_expert_W2[2*i] = lo;
        if (2*i + 1 < exp_total) s_expert_W2[2*i + 1] = hi;
    }
    for (int i = tid; i < (num_experts + 1) / 2; i += block_size) {
        float lo, hi;
        unpack_int4_gen(expert_b2_q[i], expert_b2_scale, lo, hi);
        s_expert_b2[2*i] = lo;
        if (2*i + 1 < num_experts) s_expert_b2[2*i + 1] = hi;
    }
    __syncthreads();

    // Per-element processing
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    float g = static_cast<float>(grad[idx]);
    float s = static_cast<float>(sharpness[idx]);
    if (!isfinite(g)) g = 0.0f;
    if (!isfinite(s)) s = 0.0f;
    const int half_d = d_model / 2;
    const int peer_input_dim = gru_hidden + 2 * d_model + 2;

    // Step 1: out_proj — project scan outputs to fwd_ctx/bwd_ctx
    float fwd_ctx[MAX_D_MODEL], bwd_ctx[MAX_D_MODEL];
    for (int dm = 0; dm < d_model; dm++) {
        float fwd_acc = 0.0f, bwd_acc = 0.0f;
        #pragma unroll
        for (int di = 0; di < 16; di++) {
            float fwd_so = fwd_scan_out[idx * 16 + di];
            float bwd_so = bwd_scan_out[idx * 16 + di];
            fwd_acc += s_out_fwd[dm * 16 + di] * fwd_so;
            bwd_acc += s_out_bwd[dm * 16 + di] * bwd_so;
        }
        fwd_ctx[dm] = fwd_acc;
        bwd_ctx[dm] = bwd_acc;
    }

    // Step 2: GRU state update
    float h_old[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++)
        h_old[gh] = __bfloat162float(gru_state[idx * gru_hidden + gh]);

    // Build GRU input vector: [g, s, fwd_ctx, bwd_ctx, h_old]
    float gru_in[2 + 2 * MAX_D_MODEL + MAX_GRU_HIDDEN];
    gru_in[0] = g; gru_in[1] = s;
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) gru_in[2 + d_model + dm] = bwd_ctx[dm];
    for (int gh = 0; gh < gru_hidden; gh++) gru_in[2 + 2 * d_model + gh] = h_old[gh];
    const int gru_in_len = 2 + 2 * d_model + gru_hidden;

    float h_new[MAX_GRU_HIDDEN];
    for (int gh = 0; gh < gru_hidden; gh++) {
        float z_raw = s_gru_bz[gh], r_raw = s_gru_br[gh];
        for (int k = 0; k < gru_in_len; k++) {
            z_raw += s_gru_Wz[gh * gru_row_len + k] * gru_in[k];
            r_raw += s_gru_Wr[gh * gru_row_len + k] * gru_in[k];
        }
        float z_gate = ptx_sigmoidf(z_raw);
        float r_gate = ptx_sigmoidf(r_raw);
        // Candidate with reset applied to h_old portion
        float h_raw = s_gru_bh[gh];
        for (int k = 0; k < gru_in_len; k++) {
            float inp_k = gru_in[k];
            if (k >= 2 + 2 * d_model) inp_k = r_gate * inp_k;  // reset h_old
            h_raw += s_gru_Wh[gh * gru_row_len + k] * inp_k;
        }
        float h_tilde = ptx_tanhf(h_raw);
        h_new[gh] = (1.0f - z_gate) * h_old[gh] + z_gate * h_tilde;
    }

    for (int gh = 0; gh < gru_hidden; gh++) {
        unsigned _rng = hash_prng(global_step * 7u + (unsigned)gh, (unsigned)idx);
        gru_state[idx * gru_hidden + gh] = float_to_bf16_stochastic(h_new[gh], _rng);
    }

    // Step 3: Multi-head PEER routing + Expert MLP
    // Build query input: [h_new, fwd_ctx, bwd_ctx, g, s]
    float q_in[MAX_GRU_HIDDEN + 2 * MAX_D_MODEL + 2];
    for (int gh = 0; gh < gru_hidden; gh++) q_in[gh] = h_new[gh];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + dm] = fwd_ctx[dm];
    for (int dm = 0; dm < d_model; dm++) q_in[gru_hidden + d_model + dm] = bwd_ctx[dm];
    q_in[gru_hidden + 2 * d_model] = g;
    q_in[gru_hidden + 2 * d_model + 1] = s;

    float total_out = 0.0f;
    for (int head = 0; head < num_heads; head++) {
        // Query projection
        float query[MAX_D_MODEL];
        for (int dm = 0; dm < d_model; dm++) {
            float acc = 0.0f;
            for (int k = 0; k < peer_input_dim; k++)
                acc += peer_query_Ws[head * d_model * peer_input_dim + dm * peer_input_dim + k] * q_in[k];
            query[dm] = acc;
        }

        // Product-key routing: argmax over each half
        float best_A = -1e30f, best_B = -1e30f;
        int idx_A = 0, idx_B = 0;
        for (int pk = 0; pk < pk_dim; pk++) {
            float score_A = 0.0f, score_B = 0.0f;
            for (int dm = 0; dm < half_d; dm++) {
                score_A += prod_keys_A[head * pk_dim * half_d + pk * half_d + dm] * query[dm];
                score_B += prod_keys_B[head * pk_dim * half_d + pk * half_d + dm] * query[half_d + dm];
            }
            if (score_A > best_A) { best_A = score_A; idx_A = pk; }
            if (score_B > best_B) { best_B = score_B; idx_B = pk; }
        }
        int expert_id = idx_A * pk_dim + idx_B;
        if (expert_id >= num_experts) expert_id = num_experts - 1;
        atomicAdd(&expert_counts[expert_id], 1);

        // Expert MLP: ReLU(W1 * g + b1) → W2 @ hidden + b2
        float head_out = s_expert_b2[expert_id];
        for (int eh = 0; eh < expert_hidden; eh++) {
            float hidden = s_expert_W1[expert_id * expert_hidden + eh] * g + s_expert_b1[expert_id * expert_hidden + eh];
            hidden = fmaxf(hidden, 0.0f);  // ReLU
            head_out += s_expert_W2[expert_id * expert_hidden + eh] * hidden;
        }
        total_out += head_out;
    }

    // Step 4: smart gradient
    float smart_grad = g + rescale * (total_out / (float)num_heads);

    // Step 5: mu EMA update
    // Q4 BF16 mu load/store with stochastic rounding
    float mu_old = __bfloat162float(mu[idx]);
    float mu_new = alpha * mu_old + (1.0f - alpha) * g;
    unsigned _mu_rng = hash_prng(global_step * 5u, (unsigned)idx);
    mu[idx] = float_to_bf16_stochastic(mu_new, _mu_rng);

    // Step 6: Adam optimizer step
    float effective_grad = smart_grad + lamb_eff * mu_new;
    // Q4 INT8 exp_avg load
    int _ea_blk = idx / 8;
    float ea_old = (float)exp_avg_q[idx] * exp_avg_scales[_ea_blk];
    float ea = beta1 * ea_old + (1.0f - beta1) * effective_grad;
    // Q4 INT8 exp_avg_sq load
    float easq_old = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_ea_blk];
    float easq = beta2 * easq_old + (1.0f - beta2) * effective_grad * effective_grad;
    // Stochastic requantize
    unsigned _ea_rng = sg2_philox_hash(global_step * 3u, (unsigned)idx);
    float _ea_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
    exp_avg_q[idx] = float_to_int8_stochastic(ea, _ea_scale, _ea_rng);
    if (idx % 8 == 0) exp_avg_scales[_ea_blk] = _ea_scale;
    unsigned _easq_rng = sg2_philox_hash(global_step * 4u, (unsigned)idx);
    float _easq_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
    exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _easq_scale, _easq_rng);
    if (idx % 8 == 0) exp_avg_sq_scales[_ea_blk] = _easq_scale;

    // Param update with weight decay
    float step_size = lr / bc1;
    float denom = sqrtf(easq / bc2) + eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * wd_eff);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_sg2_fused_elem_q4_int4_generic_d16(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor sharpness,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
